/* Optimal linear‑time implementation of the maximum sub‑array problem.
   The algorithm is Kadane's algorithm which scans the array once, keeping
   the running best prefix sum and the global maximum. */
int maximumSubarray(std::vector<int> const& x)
{
    // Edge case: empty array – follow the convention of the original
    // implementation (which never calls the function with empty input,
    // but we guard against it anyway).
    if (x.empty())
        return std::numeric_limits<int>::lowest();

    int maxEndingHere = x[0];
    int maxSoFar = x[0];

    for (size_t i = 1; i < x.size(); ++i) {
        // equivalent to:
        // maxEndingHere = std::max(x[i], maxEndingHere + x[i]);
        if (maxEndingHere > 0)
            maxEndingHere += x[i];
        else
            maxEndingHere = x[i];

        if (maxEndingHere > maxSoFar)
            maxSoFar = maxEndingHere;
    }
    return maxSoFar;
}
