/* Return the value of the smallest odd number in the vector x.
   If there is no odd number, returns std::numeric_limits<int>::max().
   The implementation is fully parallelized with OpenMP and uses
   a custom reduction to preserve the exact behavior of the original
   function while achieving better speed on an 8‑core system. */
int smallestOdd(const std::vector<int> &x) {
    const int INF = std::numeric_limits<int>::max();
    int global_min = INF;

    // Use OpenMP to find the minimum odd number in parallel
    #pragma omp parallel
    {
        int local_min = INF;
        #pragma omp for nowait
        for (std::size_t i = 0; i < x.size(); ++i) {
            const int v = x[i];
            if ((v & 1) && v < local_min) {   // v % 2 == 1 && v < local_min
                local_min = v;
            }
        }
        #pragma omp critical
        {
            if (local_min < global_min) {
                global_min = local_min;
            }
        }
    }

    return global_min;
}
