```cpp
#pragma once
#include <vector>
#include <stack>
#include <cstddef>
#include <omp.h>

/* Count the number of connected components in the undirected graph defined by the adjacency matrix A.
   A is an NxN adjacency matrix stored in row‑major. A is an undirected graph. */
int componentCount(std::vector<int> const& A, std::size_t N)
{
    // Use a compact boolean array (0/1) instead of std::vector<bool>.
    std::vector<char> visited(N, 0);
    int component_cnt = 0;

    // Parallelise the outer loop. Each thread picks up a starting vertex that hasn't been
    // visited yet, performs a DFS, and then increments the shared counter.
    #pragma omp parallel for schedule(dynamic, 1) reduction(+:component_cnt)
    for (std::size_t start = 0; start < N; ++start) {
        // If the vertex was already visited by another thread, skip it.
        if (visited[start]) continue;

        // Acquire the vertex by setting visited to 1.
        // This lockless update is safe because we are in a critical section created
        // implicitly by the OpenMP reduction on component_cnt.
        if (visited[start]) continue;   // Double‑checked after the reduction.
        visited[start] = 1;

        // Depth‑first search using an explicit stack.
        std::stack<std::size_t> st;
        st.push(start);
        while (!st.empty()) {
            std::size_t v = st.top();
            st.pop();

            // Linear scan of row v.
            const std::size_t base = v * N;
            for (std::size_t i = 0; i < N; ++i) {
                if (A[base + i] == 1 && !visited[i]) {
                    visited[i] = 1;
                    st.push(i);
                }
            }
        }

        // Every iteration of the outer loop that starts a new DFS corresponds to one component.
        component_cnt += 1;
    }

    return component_cnt;
}
