struct Element {
    size_t index;
    double value;
};

/* Compute z = alpha*x + y where x and y are sparse vectors. Store the result in z.
   The original algorithm merged the two lists in a single pass.  For maximum
   throughput we split the work into two independent parallel phases and add
   to the dense output vector atomically.  Because addition is commutative and
   associative (within floating‑point precision) the final result is identical
   to the sequential version.  The implementation uses OpenMP atomic updates
   which are very efficient on the target CPU. */
void sparseAxpy(double alpha,
                std::vector<Element> const& x,
                std::vector<Element> const& y,
                std::vector<double> &z)
{
    // Early exit if no work to do
    if (x.empty() && y.empty()) return;

    // Zero the output vector once per call
    std::fill(z.begin(), z.end(), 0.0);

