    {
        const size_t idx = x[i].index;
        const double val = alpha * x[i].value;
        // OpenMP atomic update (fast on x86‑64)
        #pragma omp atomic
        z[idx] += val;
    }

    // Add contributions from y  (value)
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < y.size(); ++i)
    {
        const size_t idx = y[i].index;
        const double val = y[i].value;
