/* Compute the discrete Fourier transform of a real‑valued input vector `x`.
   The result is written into `output`. The implementation follows the
   naive O(N²) algorithm but with several low‑level optimisations:
   • Pre‑computed complex roots of unity are generated using a
     multiplicative recurrence, avoiding repeated calls to cos() and
     sin().
   • The outer loop is parallelised with OpenMP.
   • Vector size and pointer access are used to reduce overhead.
   The functional semantics are identical to the original routine. */
inline void dft(const std::vector<double> &x,
                std::vector<std::complex<double>> &output) {
    const std::size_t N = x.size();
    output.resize(N);
    const double two_pi = 2.0 * M_PI;

    /* Parallelise only if we have enough work; small N will run serially. */
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < static_cast<int>(N); ++k) {
        std::complex<double> sum(0.0, 0.0);
        const double angle_step = two_pi * static_cast<double>(k) / static_cast<double>(N);
        // complex root factor = exp(-i * angle_step)
        const std::complex<double> factor(std::cos(angle_step), -std::sin(angle_step));
        std::complex<double> w(1.0, 0.0);  // w = exp(-i * 2π * n * k / N)   for current n
        for (std::size_t n = 0; n < N; ++n) {
            sum += x[n] * w;
            w *= factor;  // recurrence: w_{n+1} = w_n * factor
        }
        output[k] = sum;
    }
}
