/*  Finds the length of the shortest path between source and dest in an
 *  undirected graph represented by an N×N adjacency matrix A (row‑major).
 *  The matrix is stored as a flat std::vector<int> where A[i*N + j] is
 *  1 if i and j are adjacent, otherwise 0.  The graph is assumed to be
 *  connected.  The algorithm runs in O(N + E) time, where E is the number
 *  of edges, and uses a simple array‑based FIFO queue for the BFS.
 *
 *  Parameters
 *  ----------
 *  A      : adjacency matrix of the graph (flattened).
 *  N      : number of vertices.
 *  source : start vertex id.
 *  dest   : target vertex id.
 *
 *  Returns
 *  -------
 *  Length of the shortest path from source to dest, or std::numeric_limits<int>::max()
 *  if no path exists (shouldn't happen for a connected graph).
 */
inline int shortestPathLength(const std::vector<int>& A, std::size_t N,
                               int source, int dest)
{
    if (source == dest) return 0;

    // Build adjacency lists once
    std::vector<std::vector<int>> adj(N);
    adj.reserve(N);
    for (std::size_t i = 0; i < N; ++i) {
        std::vector<int> nbrs;
        nbrs.reserve(N);
        const std::size_t row = i * N;
        for (std::size_t j = 0; j < N; ++j) {
            if (A[row + j]) nbrs.push_back(static_cast<int>(j));
        }
        adj[i] = std::move(nbrs);
    }

    // BFS using a simple ring buffer
    std::vector<int> queue(N);
    std::vector<int> dist(N, -1);
    std::size_t head = 0, tail = 0;

    dist[source] = 0;
    queue[tail++] = source;

    while (head < tail) {
        int v = queue[head++];
        int d = dist[v] + 1;
        for (int u : adj[v]) {
            if (dist[u] == -1) {
                dist[u] = d;
                if (u == dest) return d;
                queue[tail++] = u;
            }
        }
    }
    return std::numeric_limits<int>::max();
}
