    if (n < 2) return 0.0;

    // Use squared distance to avoid expensive pow/sqrt until the end.
    const double INF = std::numeric_limits<double>::max();
    double minDistSq = INF;

    /*  Parallel reduction over i. Each thread keeps its own local
     *  minDistSq to avoid false sharing.  OpenMP's "reduction" clause
     *  is enough – GCC implements it efficiently on x86‑64.
     */
#pragma omp parallel for schedule(static) reduction(min:max:minDistSq)
    for (size_t i = 0; i < n - 1; ++i) {
        const Point& pi = points[i];
        for (size_t j = i + 1; j < n; ++j) {
            const double dx  = points[j].x - pi.x;
            const double dy  = points[j].y - pi.y;
            const double d2  = dx * dx + dy * dy;
            if (d2 < minDistSq) minDistSq = d2;
        }
    }

    // Convert back to normal Euclidean distance.
    return std::sqrt(minDistSq);
