#include <cstdlib>
#include <omp.h>

/*
 * Compute the inclusive prefix sum of the vector `x` into `output`.
 * The function preserves the exact semantics of std::inclusive_scan
 * but uses a parallel algorithm that scales on the target x86‑64
 * hardware with 8 OpenMP threads.
 */
inline void prefixSum(std::vector<int64_t> const& x, std::vector<int64_t>& output)
{
    const std::size_t n = x.size();
    if (n == 0) return;

    /* Ensure output has the same size as input */
    if (output.size() != n) output.resize(n);

    /* Use a block size that gives about equal work per thread */
    const std::size_t num_threads = std::min(std::size_t(omp_get_max_threads()), n);
    const std::size_t block = (n + num_threads - 1) / num_threads;

    /* Step 1: each thread computes a local prefix sum and records its
     * total.  The totals are stored in a temporary vector `sums`. */
    std::vector<int64_t> sums(num_threads, 0);

#pragma omp parallel num_threads(num_threads)
    {
        const std::size_t tid = omp_get_thread_num();
        const std::size_t start = tid * block;
        const std::size_t end   = std::min(start + block, n);

        int64_t local_sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            local_sum += x[i];
            output[i] = local_sum;
        }
        sums[tid] = local_sum;
    }

    /* Step 2: compute the prefix sum of the block totals sequentially. */
    for (std::size_t i = 1; i < num_threads; ++i) {
        sums[i] += sums[i - 1];
    }

    /* Step 3: add the preceding block total to each element in the block
     * (except the first block). */
#pragma omp parallel for schedule(static)
    for (std::size_t tid = 1; tid < num_threads; ++tid) {
        const std::size_t start = tid * block;
        const std::size_t end   = std::min(start + block, n);
        const int64_t offset = sums[tid - 1];
        for (std::size_t i = start; i < end; ++i) {
            output[i] += offset;
        }
    }
}
