#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Compute Y = A * X where
 *      - A is M×K sparse matrix in COO format,
 *      - X is K×N sparse matrix in COO format,
 *      - Y is a dense M×N matrix stored in row-major order.
 *
 * The implementation uses an auxiliary hash table to group the
 * non‑zero entries of X by their row index.  The outer loop over A is
 * parallelised with OpenMP and each thread writes to its own local
 * output buffer; the local results are summed into Y after the loop.
 */
static inline void spmm(const std::vector<COOElement> &A,
                        const std::vector<COOElement> &X,
                        std::vector<double> &Y,
                        size_t M, size_t K, size_t N)
{
    // Initialise Y with zeros
    Y.assign(M * N, 0.0);

    /* Build a hash table from column index of A (which is row index of X)
       to the list of X entries with that row. */
    std::unordered_multimap<size_t, const COOElement*> x_by_row;
    x_by_row.reserve(X.size() * 2);     // a rough over‑allocation for speed
    for (const auto &x : X)
        x_by_row.emplace(x.row, &x);

    // Determine the number of OpenMP threads
    const int nthreads = omp_get_max_threads();

    // Each thread keeps a private Y buffer
    std::vector<std::vector<double>> localY(nthreads, std::vector<double>(M * N, 0.0));

#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::vector<double> &local = localY[tid];

#pragma omp for schedule(dynamic, 256)
        for (size_t ai = 0; ai < A.size(); ++ai)
        {
            const COOElement &a = A[ai];
            // Find all X entries with a.row == x.row
            auto range = x_by_row.equal_range(a.column);
            for (auto it = range.first; it != range.second; ++it)
            {
                const COOElement &x = *(it->second);
                local[a.row * N + x.column] += a.value * x.value;
            }
        }
    }

    // Sum all local results into the final matrix Y
    for (size_t t = 0; t < static_cast<size_t>(nthreads); ++t)
    {
        const std::vector<double> &local = localY[t];
        for (size_t idx = 0; idx < M * N; ++idx)
            Y[idx] += local[idx];
    }
}
