double smallestArea(std::vector<Point> const& points) {
    const size_t n = points.size();
    if (n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

    // Parallelize outer loop and use reduction to keep the smallest area.
    #pragma omp parallel for schedule(static) reduction(min:minArea)
    for (size_t i = 0; i < n - 2; ++i) {
        const Point& pi = points[i];
        for (size_t j = i + 1; j < n - 1; ++j) {
            const Point& pj = points[j];
            for (size_t k = j + 1; k < n; ++k) {
                const double area = triArea(pi, pj, points[k]);
                if (area < minArea) {
                    minArea = area;
                }
            }
        }
    }

