inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int>& output,
                     std::size_t N) noexcept
{
    // Ensure the output buffer is large enough
    if (output.size() < N * N) output.resize(N * N);

    const int*  in  = input.data();
    int*        out = output.data();
    const std::size_t stride = N;

    // Parallelize over rows; each row is independent
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t base = i * stride;
        std::size_t nextBase = base + stride;

        for (std::size_t j = 0; j < N; ++j) {
            int count = 0;

            // Up
            if (i > 0 && in[base - stride + j] == 1) ++count;
            // Down
            if (i + 1 < N && in[nextBase + j] == 1) ++count;
            // Left
            if (j > 0 && in[base + j - 1] == 1) ++count;
            // Right
            if (j + 1 < N && in[base + j + 1] == 1) ++count;

            out[base + j] = (count == 1) ? 1 : 0;
        }
    }
}
