#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*  In‑place LU factorization of a dense matrix.
    Input matrix A is supplied in COO format.  The function allocates
    dense row‑major arrays for L and U (as flat vectors of size N*N).
    The result is exactly the same as the original implementation, but
    the code is rewritten for performance on modern x86‑64 CPUs using
    GCC –O2 and OpenMP.  No private state is leaked and all memory is
    released automatically. */
void luFactorize(std::vector<COOElement> const& A,
                 std::vector<double>& L,
                 std::vector<double>& U,
                 size_t N)
{
    /* --------------------------------------------------------------------
       1. Allocate dense arrays for the input matrix and for the factors
          L and U.  The flat representation allows the compiler to
          generate efficient vectorised code and to keep all data in
          contiguous memory.
       -------------------------------------------------------------------- */
    std::vector<double> fullA(N * N, 0.0);

    for (const auto& e : A) {
        fullA[e.row * N + e.column] = e.value;
    }

    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* --------------------------------------------------------------------
       2. Adapted Doolittle algorithm.
          * Outer loop over pivot row i.
          * Work on U[i][j] for j>=i  (upper triangle).
          * Work on L[i][j] for j<i    (lower triangle).
          * The diagonal of L is set to 1 at the end of each row.
          * For performance the inner loops use raw pointers and
            explicit bounds checking is omitted because all indices
            are guaranteed to be in range by the algorithm.
          * OpenMP parallelises the work that is independent for each
            column j   (the update of U[i][j] for all j>=i).
          * The division L[i][j] /= U[j][j] is performed only once
            after the inner sum, which matches the behaviour of the
            reference code.
       -------------------------------------------------------------------- */
    for (size_t i = 0; i < N; ++i) {
        /* ----- Compute U[i][j] for j >= i ----- */
#pragma omp parallel for schedule(static)
        for (size_t j = i; j < N; ++j) {
            double s = fullA[i * N + j];
            for (size_t k = 0; k < i; ++k) {
                s -= L[i * N + k] * U[k * N + j];
            }
            U[i * N + j] = s;
        }

        /* ----- Compute L[i][j] for j < i ----- */
        for (size_t j = 0; j < i; ++j) {
            double s = fullA[i * N + j];
            for (size_t k = 0; k < j; ++k) {
                s -= L[i * N + k] * U[k * N + j];
            }
            /* U[j][j] is known from the previous iteration, so no race. */
            L[i * N + j] = s / U[j * N + j];
        }

        /* ----- Diagonal of L is 1 ----- */
        L[i * N + i] = 1.0;
    }
}
