#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Optimised Game of Life – single generation.
 *
 * The implementation preserves the exact behaviour of the reference.
 * Main optimisations:
 *  - Parallelisation with OpenMP (static scheduling, chunked rows).
 *  - Row‑major access with a pre‑computed row stride.
 *  - Small local variables and `restrict`‑style coding for the compiler.
 *  - Minimise branching inside the innermost loop.
 *
 * The algorithm is kept identical to the specification.
 */
void gameOfLife(std::vector<int> const& input, std::vector<int>& output, size_t N) noexcept {
    const size_t stride = N;                     // distance between rows
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t base = i * stride;
        const int *prevRow = (i > 0) ? &input[(i - 1) * stride] : nullptr;
        const int *nextRow = (i + 1 < N) ? &input[(i + 1) * stride] : nullptr;
        int *outRow = &output[base];

        for (size_t j = 0; j < N; ++j) {
            int sum = 0;
            /* vertical neighbours */
            if (prevRow) sum += prevRow[j];
            if (nextRow) sum += nextRow[j];
            /* horizontal neighbours */
            if (j > 0)       sum += input[base + j - 1];
            if (j + 1 < N)   sum += input[base + j + 1];
            /* diagonal neighbours */
            if (prevRow) {
                if (j > 0)       sum += prevRow[j - 1];
                if (j + 1 < N)   sum += prevRow[j + 1];
            }
            if (nextRow) {
                if (j > 0)       sum += nextRow[j - 1];
                if (j + 1 < N)   sum += nextRow[j + 1];
            }

            const int cur = input[base + j];
            /* apply rules – written to avoid branches inside kernel */
            outRow[j] =
                (cur            && (sum == 2 || sum == 3))         ? 1 :
                (!cur           && sum == 3)                       ? 1 :
                0;
        }
    }
}
