#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <cstddef>
#include <omp.h>

struct COOElement
{
    std::size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format.
   x and b are dense vectors with N elements.  */
void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double>& x,
                       std::size_t N)
{
    // ---- Create a dense matrix in row-major order -------------------------
    std::vector<double> matrix(N * N, 0.0);

    for (const auto& el : A)
    {
        matrix[el.row * N + el.column] = el.value;
    }

    // ---- Work copies -------------------------------------------------------
    std::vector<double> b_copy = b;       // make a copy of b
    x.assign(N, 0.0);                     // result vector

    // ---- Gaussian elimination with partial pivoting ----------------------
    for (std::size_t i = 0; i < N; ++i)
    {
        /*--- Pivot selection (parallelized search) ------------------------*/
        double maxVal = std::abs(matrix[i * N + i]);
        std::size_t maxRow = i;

        #pragma omp parallel
        {
            double localMax = maxVal;
            std::size_t localRow = maxRow;
            #pragma omp for schedule(static)
            for (std::size_t k = i + 1; k < N; ++k)
            {
                double val = std::abs(matrix[k * N + i]);
                if (val > localMax)
                {
                    localMax = val;
                    localRow = k;
                }
            }

            #pragma omp critical
            {
                if (localMax > maxVal)
                {
                    maxVal = localMax;
                    maxRow = localRow;
                }
            }
        }

        /*--- Swap the pivot row with the current row ----------------------*/
        if (maxRow != i)
        {
            for (std::size_t k = i; k < N; ++k)
            {
                std::swap(matrix[i * N + k], matrix[maxRow * N + k]);
            }
            std::swap(b_copy[i], b_copy[maxRow]);
        }

        /*--- Eliminate rows below the pivot (parallelized) ----------------*/
        #pragma omp parallel for schedule(static)
        for (std::size_t k = i + 1; k < N; ++k)
        {
            if (matrix[i * N + i] == 0.0)
                continue;   // singular pivot; keep as is

            double factor = -matrix[k * N + i] / matrix[i * N + i];
            matrix[k * N + i] = 0.0; // explicitly zero the pivot column

            for (std::size_t j = i + 1; j < N; ++j)
            {
                matrix[k * N + j] += factor * matrix[i * N + j];
            }
            b_copy[k] += factor * b_copy[i];
        }
    }

    // ---- Back substitution (serial) --------------------------------------
    for (std::ptrdiff_t i = static_cast<std::ptrdiff_t>(N) - 1; i >= 0; --i)
    {
        double diag = matrix[i * N + i];
        x[i] = b_copy[i] / diag;
        for (std::ptrdiff_t k = i - 1; k >= 0; --k)
        {
            b_copy[k] -= matrix[k * N + i] * x[i];
        }
    }
}
