#pragma once
#include <vector>
#include <algorithm>
#include <cmath>

struct Point {
    double x, y;
};

constexpr double EPS = 1e-12;

// Vector cross product (b‑a) × (c‑a)
inline double cross(const Point& a, const Point& b, const Point& c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

// Euclidean distance without pow/sqrt overhead
inline double dist(const Point& a, const Point& b)
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

/* Return the perimeter of the smallest convex polygon that contains all the points in the vector points.
   The function keeps the exact behavior of the original but is rewritten for performance. */
double convexHullPerimeter(const std::vector<Point>& points)
{
    const size_t n = points.size();
    if (n < 3) return 0.0;

    // copy and sort points once (O(n log n))
    std::vector<Point> sorted = points;
    std::sort(sorted.begin(), sorted.end(), [](const Point& a, const Point& b) {
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    });

    // Monotone chain algorithm (O(n))
    std::vector<Point> hull;
    hull.reserve(2 * n);

    // lower hull
    for (size_t i = 0; i < n; ++i) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], sorted[i]) <= 0.0)
            hull.pop_back();
        hull.push_back(sorted[i]);
    }

    // upper hull
    size_t lowerSize = hull.size();
    for (size_t i = n - 1; i > 0; --i) {
        while (hull.size() > lowerSize &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], sorted[i - 1]) <= 0.0)
            hull.pop_back();
        hull.push_back(sorted[i - 1]);
    }

    // Remove duplicate of the first point
    hull.pop_back();

    // Compute perimeter
    double perimeter = 0.0;
    for (size_t i = 0; i < hull.size(); ++i)
        perimeter += dist(hull[i], hull[(i + 1) % hull.size()]);

    return perimeter;
}
