void convexHull(const std::vector<Point>& points, std::vector<Point>& hull) noexcept {
    const size_t n = points.size();
    if (n < 3) {                 // trivial cases
        hull = points;
        return;
    }

    // ---- 1. Sort points lexicographically (x, then y) ----------------------
    // Use a copy data buffer to avoid modifying input vector
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) noexcept {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    // ---- 2. Build hull -----------------------------------------------
    // Pre‑allocate maximum possible size 2*n
    std::vector<Point> buf;
    buf.resize(2 * n);
    size_t k = 0;                   // current hull size (index of next free slot)

    // Lower hull
    for (size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(buf[k-2], buf[k-1], sorted[i]) <= 0) --k;
        buf[k++] = sorted[i];
    }

    // Upper hull (skip last point to avoid duplication)
    for (size_t i = n-1; i > 0; --i) {
        while (k >= (size_t) (1 + k - n) && cross(buf[k-2], buf[k-1], sorted[i-1]) <= 0) --k;
        buf[k++] = sorted[i-1];
    }

    // Trim to final size (last point equals first)
    buf.resize(k-1);
    hull.swap(buf);                  // avoids copy
}
