#pragma once
#include <vector>
#include <omp.h>

//==============================================================================
// 2‑D Jacobi stencil – 5‑point average.
// The routine is fully parallelised with OpenMP (4 threads, 8‑way cache‑friendly
// loop layout).  The original logic is preserved:  out[i,j] = (in[i,j] +
// in[i‑1,j] + in[i+1,j] + in[i,j‑1] + in[i,j+1]) / 5.0, with zero‑padding
// outside the domain.
//
// No function signature changes are made – the harness can call this directly.
//
//==============================================================================

void jacobi2D(const std::vector<double> &input, std::vector<double> &output, size_t N)
{
    // Gracefully handle a degenerate grid
    if (N == 0) return;

    // Allocate a padded temporary grid to avoid bounds checks
    const size_t padded = N + 2;                     // 1 cell border on each side
    std::vector<double> padded_in(padded * padded, 0.0);

    // Copy the original data into the centre of the padded grid
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i)
        for (size_t j = 0; j < N; ++j)
            padded_in[(i + 1) * padded + (j + 1)] = input[i * N + j];

    // Perform the stencil on the padded grid.  The loops are collapsed
    // to a single 2‑D iteration space to give the compiler a better
    // chance of vectorising and to keep the thread chunks contiguous.
    #pragma omp parallel for collapse(2) \
        schedule(static, (N * padded) / 8 * 8)  // auto‑chunking for 8 threads
    for (size_t i = 1; i <= N; ++i)           // i ranges 1..N
    {
        const size_t base = i * padded;
        const size_t prev = (i - 1) * padded;
        const size_t next = (i + 1) * padded;
        for (size_t j = 1; j <= N; ++j)
        {
            const double sum =
                padded_in[base + j]          + // centre
                padded_in[prev + j]          + // north
                padded_in[next + j]          + // south
                padded_in[base + j - 1]      + // west
                padded_in[base + j + 1];        // east

            output[(i - 1) * N + (j - 1)] = sum / 5.0;
        }
    }
}
