#pragma once
#include <vector>
#include <cstddef>
#include <immintrin.h>
#include <omp.h>

/* Optimized matrix‑vector product.
 *
 * A is an M×N matrix stored in row‑major order.
 * x has N elements, y has M elements.
 *
 * Uses a combination of:
 *   - OpenMP parallelism over the outer dimension
 *   - SIMD vectorisation with AVX2 intrinsics
 *   - Blocking to improve cache utilisation
 *   - Small‑matrix unrolling for the inner loop
 */
inline void gemv(const std::vector<double> &A,
                 const std::vector<double> &x,
                 std::vector<double>       &y,
                 size_t M, size_t N)
{
    constexpr size_t simd_width = 4;       // AVX2 256‑bit -> 4 doubles
    constexpr size_t block_rows = 64;     // rows per cache block (tune if needed)
    constexpr size_t block_cols = 64;     // columns per cache block (tune if needed)

    // Ensure output vector has the right size
    y.assign(M, 0.0);

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < M; i += block_rows) {
        size_t ib = std::min(block_rows, M - i);

        for (size_t ii = 0; ii < ib; ++ii) {
            size_t row = i + ii;
            __m256d acc0 = _mm256_setzero_pd();

            size_t j = 0;
            // First, process vectorised chunks of 4 columns
            for (; j + simd_width <= N; j += simd_width) {
                __m256d col = _mm256_loadu_pd(&x[j]);
                __m256d mat = _mm256_loadu_pd(&A[row * N + j]);
                acc0 = _mm256_fmadd_pd(mat, col, acc0);
            }

            // Horizontal addition of acc0
            double tmp[4];
            _mm256_storeu_pd(tmp, acc0);
            double sum = tmp[0] + tmp[1] + tmp[2] + tmp[3];

            // Handle remaining columns serially
            for (; j < N; ++j) {
                sum += A[row * N + j] * x[j];
            }

            y[row] = sum;
        }
    }
}
