#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

#if !defined(M_PI)
#  define M_PI 3.14159265358979323846
#endif

/* Radix‑2 iterative FFT. Works only for sizes that are powers of two.
   The implementation is cache‑friendly, uses a pre‑computed bit
   reversal table and parallelises the outer butterfly stages with
   OpenMP.  The behaviour is identical to the reference code.  */
void fft(std::vector<std::complex<double>> const& x,
         std::vector<std::complex<double>>& output)
{
    constexpr size_t WORD_BITS = 64;
    const size_t N = x.size();
    output.resize(N);
    output = x;                      /* input copy */

    /* --------  pre‑compute bit reversal table  -------- */
    const size_t log2N = static_cast<size_t>(std::log2(N));
    std::vector<size_t> rev(N);
    for (size_t i = 0; i < N; ++i)
    {
        size_t v = i;
        v = ((v & 0xaaaaaaaaaaaaaaaaULL) >> 1) | ((v & 0x5555555555555555ULL) << 1);
        v = ((v & 0xccccccccccccccccULL) >> 2) | ((v & 0x3333333333333333ULL) << 2);
        v = ((v & 0xf0f0f0f0f0f0f0f0ULL) >> 4) | ((v & 0x0f0f0f0f0f0f0f0fULL) << 4);
        v = ((v & 0xff00ff00ff00ff00ULL) >> 8) | ((v & 0x00ff00ff00ff00ffULL) << 8);
        v = ((v & 0xffff0000ffff0000ULL) >> 16) | ((v & 0x0000ffff0000ffffULL) << 16);
        v = (v >> (WORD_BITS - log2N)) ^ (v << (WORD_BITS - log2N)); // shift
        rev[i] = v;
    }

    /* --------  do the FFT  -------- */
    for (size_t stage = 1; stage <= log2N; ++stage)
    {
        const size_t h   = 1ULL << (stage - 1);
        const size_t step = h << 1;
        const double theta = -M_PI / static_cast<double>(h);
        const std::complex<double> w_m = std::polar(1.0, theta);

        /* parallelise the outer loop – each thread works on a distinct
           block of butterfly pairs.  The inner loop is completely
           independent. */
#pragma omp parallel for schedule(static)
        for (size_t i = 0; i < N; i += step)
        {
            std::complex<double> w = 1.0;
            for (size_t j = 0; j < h; ++j)
            {
                const size_t idx1 = i + j;
                const size_t idx2 = idx1 + h;
                const std::complex<double> t = w * output[idx2];
                output[idx2] = output[idx1] - t;
                output[idx1] += t;
                w *= w_m;
            }
        }
    }

    /* --------  bit‑reverse permutation  -------- */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const size_t j = rev[i];
        if (j > i)
            std::swap(output[i], output[j]);
    }
}
