```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row‑major. x and b have N elements.
   Example:

   input:  A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
inline void solveLinearSystem(std::vector<double> const &A,
                              std::vector<double> const &b,
                              std::vector<double> &x,
                              std::size_t N)
{
    // -------------------------------------------------------------
    // Work on copies to preserve input data.  Copies are small
    // (N² doubles) and are allocated once per call.
    // -------------------------------------------------------------
    std::vector<double> A_copy(A);           // row‑major copy of A
    std::vector<double> b_copy(b);           // copy of b

    // -------------------------------------------------------------
    // Gaussian elimination (forward elimination)
    // -------------------------------------------------------------
    for (std::size_t i = 0; i < N - 1; ++i) {
        double pivot = A_copy[i * N + i];
        if (pivot == 0.0)                   // singular matrix → abort
            return;

        double inv_pivot = 1.0 / pivot;      // reuse for speed
        std::size_t ai = i * N;              // index of start of row i

        #pragma omp parallel for schedule(static)
        for (std::size_t j = i + 1; j < N; ++j) {
            double factor = A_copy[j * N + i] * inv_pivot;
            std::size_t aj = j * N;          // index of start of row j

            // Vectorised inner loop; starts at column i
            for (std::size_t k = i; k < N; ++k) {
                A_copy[aj + k] -= factor * A_copy[ai + k];
            }
            b_copy[j] -= factor * b_copy[i];
        }
    }

    // -------------------------------------------------------------
    // Back substitution
    // -------------------------------------------------------------
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        std::size_t ai = i * N;
        for (std::size_t j = i + 1; j < N; ++j) {
            sum += A_copy[ai + j] * x[j];
        }
        x[i] = (b_copy[i] - sum) / A_copy[ai + i];
    }
}
