#pragma once
#include <cmath>
#include <complex>
#include <vector>
#include <algorithm>
#include <cstring>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

//---------------------------------------------------------------------
// iterative iterative decimation‑in‑time FFT (forward)
//---------------------------------------------------------------------
inline void fft_helper(std::vector<std::complex<double>>& x)
{
    const size_t N = x.size();
    if (N <= 1) return;

    // bit reversal permutation (in‑place)
    {
        const unsigned int shift = 32 - static_cast<unsigned int>(std::log2(N));
        std::vector<size_t> rev(N);
        for (size_t i = 0; i < N; ++i) {
            unsigned int b = static_cast<unsigned int>(i);
            b = ((b & 0xaaaaaaaaU) >> 1) | ((b & 0x55555555U) << 1);
            b = ((b & 0xccccccccU) >> 2) | ((b & 0x33333333U) << 2);
            b = ((b & 0xf0f0f0f0U) >> 4) | ((b & 0x0f0f0f0fU) << 4);
            b = ((b & 0xff00ff00U) >> 8) | ((b & 0x00ff00ffU) << 8);
            b = ((b >> 16) | (b << 16)) >> shift;
            rev[i] = b;
        }
        for (size_t i = 0; i < N; ++i)
            if (rev[i] > i) std::swap(x[i], x[rev[i]]);
    }

    // pre‑compute twiddle factors
    const size_t logN = static_cast<size_t>(std::log2(N));
    std::vector<std::complex<double>> wlog(logN+1);
    for (size_t s = 0; s <= logN; ++s) {
        const double angle = -M_PI / (1ULL << s);
        wlog[s] = std::polar(1.0, angle);
    }

    // FFT iterations
#pragma omp parallel for
    for (size_t s = 0; s < logN; ++s) {
        const size_t m = 1ULL << (s+1);          // stage size
        const size_t half_m = m >> 1;
        const std::complex<double> wm = wlog[s+1];
        for (size_t k = 0; k < N; k += m) {
            std::complex<double> w = 1.0;
            for (size_t j = 0; j < half_m; ++j) {
                std::complex<double> u = x[k + j];
                std::complex<double> t = w * x[k + j + half_m];
                x[k + j] = u + t;
                x[k + j + half_m] = u - t;
                w *= wm;
            }
        }
    }
}

//---------------------------------------------------------------------
// Inverse FFT (using conjugate, forward FFT, conjugate, scale)
//---------------------------------------------------------------------
inline void ifft(std::vector<std::complex<double>>& x)
{
    for (auto& c : x) c = std::conj(c);          // conjugate
    fft_helper(x);                               // forward
    for (auto& c : x) c = std::conj(c);          // conjugate again
    const double invN = 1.0 / static_cast<double>(x.size());
    for (auto& c : x) c *= invN;                 // scale
