/* Compute the prefix sum array of the vector x and return its sum.
   Example:
   input: [-7, 2, 1, 9, 4, 8]
   output: 15
*/
int64_t sumOfPrefixSum(std::vector<int64_t> const& x) {
    const std::size_t n = x.size();
    if (n == 0) return 0;

    std::vector<int64_t> prefixSum(n);
    const int num_threads = omp_get_max_threads();
    const std::size_t blockSize = (n + num_threads - 1) / num_threads;

    // Temporary array to hold block sums (size = num_threads + 1)
    std::vector<int64_t> blockSums(num_threads + 1, 0);

    // First pass: compute local prefix sums and block sums
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * blockSize;
        const std::size_t end   = std::min(start + blockSize, n);
        int64_t localSum = 0;
        for (std::size_t i = start; i < end; ++i) {
            localSum += x[i];
            prefixSum[i] = localSum;
        }
        blockSums[tid + 1] = localSum; // store block sum
    }

    // Prefix sum over block sums to get offsets
    for (int i = 1; i <= num_threads; ++i) {
        blockSums[i] += blockSums[i - 1];
    }

    // Second pass: add offsets to each block
    #pragma omp parallel for schedule(static)
    for (int tid = 0; tid < num_threads; ++tid) {
        const std::size_t start = tid * blockSize;
        const std::size_t end   = std::min(start + blockSize, n);
        const int64_t offset = blockSums[tid];
        for (std::size_t i = start; i < end; ++i) {
            prefixSum[i] += offset;
        }
    }

    // Finally, sum the prefix array in parallel
    int64_t total = 0;
    #pragma omp parallel for reduction(+:total)
    for (std::size_t i = 0; i < n; ++i) {
        total += prefixSum[i];
    }

    return total;
}
