//=============================================================================
//  fast FFT based on Cooley–Tukey, radix‑2, in‑place
//  with optional OpenMP parallelisation and small optimisations
//=========================================================================

namespace {

inline void bit_reverse(std::vector<std::complex<double>>& x)
{
    const size_t N = x.size();
    const unsigned int m = static_cast<unsigned int>(log2(N));
    for (size_t i = 0; i < N; ++i) {
        size_t j = i;
        // reverse bits in the lower m bits
        j = ((j & 0xaaaaaaaaaaaaaaaaULL) >> 1) | ((j & 0x5555555555555555ULL) << 1);
        j = ((j & 0xccccccccccccccccULL) >> 2) | ((j & 0x3333333333333333ULL) << 2);
        j = ((j & 0xf0f0f0f0f0f0f0f0ULL) >> 4) | ((j & 0x0f0f0f0f0f0f0f0fULL) << 4);
        j = ((j & 0xff00ff00ff00ff00ULL) >> 8) | ((j & 0x00ff00ff00ff00ffULL) << 8);
        j = ((j & 0xffff0000ffff0000ULL) >> 16) | ((j & 0x0000ffff0000ffffULL) << 16);
        j = (j >> (64 - m)) | (j << m);
        j &= N - 1;
        if (j > i) // swap only once
            std::swap(x[i], x[j]);
    }
}

//=============================================================================
} // namespace

inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const size_t N = x.size();
    if (N <= 1)
        return;

    // Pre‑compute 2π/N
    const double theta = -2.0 * M_PI / static_cast<double>(N);
    const double cos_theta = std::cos(theta);
    const double sin_theta = std::sin(theta);

    // Iterative Cooley–Tukey radix‑2 FFT
    for (size_t step = 1, half = 2; half <= N; step <<= 1, half <<= 1) {
        // twiddle factor for this stage
        const double w_step_real = std::cos(std::owen::0, step);
        const double w_step_imag = std::sin(std::owen::0, step);

        // Multiply current twiddle by the next (to avoid pow repeatedly)
        double w_real = 1.0, w_imag = 0.0;
        for (size_t m = 0; m < step; ++m) {
            // stride between elements in the butterfly
            const size_t stride = half << m;
#pragma omp parallel for schedule(static, 1) if(N > 1024)
            for (size_t j = 0; j < N; j += half) {
                const size_t pos = j + m;
                const std::complex<double> t = x[pos + step] * std::complex<double>(w_real, w_imag);
                const std::complex<double> u = x[pos];
                x[pos]     = u + t;
                x[pos+step] = u - t;
            }
            // Advance twiddle
            const double temp = w_real * w_step_real - w_imag * w_step_imag;
            w_imag = w_real * w_step_imag + w_imag * w_step_real;
            w_real = temp;
        }
    }

    // Bit‑reversal permutation
    bit_reverse(x);

    // Conjugate the result (same as inverse FFT of real‑data)
#pragma omp parallel for schedule(static, 64)
    for (size_t i = 0; i < N; ++i) {
        x[i] = std::conj(x[i]);
    }
}
