 * Return the index of the last Book item in the vector `books` where
 * Book.pages is less than 100.  If no such book exists, return books.size().
 */
size_t findLastShortBook(std::vector<Book> const& books) {
    // Use a parallel reduction to find the greatest index satisfying the
    // condition.  The reduction variable is initialized to -1 to indicate
    // that no qualifying book has been seen yet.
    int64_t best = -1;
    #pragma omp parallel for reduction(max:best)
    for (int64_t i = static_cast<int64_t>(books.size()) - 1; i >= 0; --i) {
        if (books[static_cast<size_t>(i)].pages < 100) {
            best = i;
        }
    }
    return static_cast<size_t>(best == -1 ? books.size() : best);
}
