/* Return the index of the first even number in the vector x.
   Examples:
   input: [7, 3, 9, 5, 5, 7, 2, 9, 12, 11]
   output: 6
   input: [3, 8, 9, 9, 3, 4, 8, 6]
   output: 1
*/
inline size_t findFirstEven(const std::vector<int>& x) {
    const size_t n = x.size();
    const int* data = x.data();

    /* Use a small loop unroll for a few cycles of vectorisation,
       while keeping a simple test per element to minimise branch cost. */
    size_t i = 0;
    // Unroll 2 iterations per loop to reduce loop overhead.
    for (; i + 1 < n; i += 2) {
        if ((data[i] & 1) == 0) return i;
        if ((data[i + 1] & 1) == 0) return i + 1;
    }

    // Handle any remaining element.
    for (; i < n; ++i) {
        if ((data[i] & 1) == 0) return i;
    }
    return n; // No even number found.
}
