// Simple a structure avoiding std::complex overhead
struct Complex
{
    double re, im;
    Complex(double r = 0.0, double i = 0.0) noexcept : re(r), im(i) {}
    Complex operator+(Complex const& o) const noexcept { return {re + o.re, im + o.im}; }
    Complex operator-(Complex const& o) const noexcept { return {re - o.re, im - o.im}; }
    Complex operator*(Complex const& o) const noexcept
    {
        return {re * o.re - im * o.im, re * o.im + im * o.re};
    }
    Complex operator*(double f) const noexcept { return {re * f, im * f}; }
};

inline Complex mul_by_T(Complex a, Complex t) noexcept
{
    // a * t
    return a * t;
}

// Pre‑computed bit‑reversal tables per power‑of‑two size
static std::unordered_map<std::size_t, std::vector<std::size_t>> rev_cache;
static std::mutex rev_lock;

static std::vector<std::size_t> get_bitrev(std::size_t N)
{
    std::lock_guard<std::mutex> lk(rev_lock);
    auto it = rev_cache.find(N);
    if (it != rev_cache.end())
        return it->second;

    std::vector<std::size_t> rev(N);
    int logN = 0;
    std::size_t tmpN = N;
    while (tmpN >>= 1) ++logN;

    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t rev_i = 0, x = i;
        for (int j = 0; j < logN; ++j)
        {
            rev_i = (rev_i << 1) | (x & 1);
            x >>= 1;
        }
        rev[i] = rev_i;
    }
    rev_cache.emplace(N, rev);
    return rev;
}

// Main FFT routine
inline void fft(const std::vector<std::complex<double>>& x,
                std::vector<double>& r, std::vector<double>& i)
{
    const std::size_t N = x.size();
    if (N == 0) return;
    // Ensure r and i are sized correctly
    r.resize(N);
    i.resize(N);

    // Copy input into our own complex array
    std::vector<Complex> a(N);
    for (std::size_t k = 0; k < N; ++k)
        a[k] = Complex(x[k].real(), x[k].imag());

    // Bit‑reverse ordering
    const std::vector<std::size_t> rev = get_bitrev(N);
    for (std::size_t k = 0; k < N; ++k)
        if (rev[k] > k)
            std::swap(a[k], a[rev[k]]);

    // Pre‑compute twiddle factors for the whole transform
    std::vector<Complex> twiddles(N / 2);
    const double PI = std::acos(-1.0);
    for (std::size_t k = 0; k < N / 2; ++k)
    {
        double phase = -2 * PI * k / N;
        twiddles[k] = Complex(std::cos(phase), std::sin(phase));
    }

    // Iterative radix‑2 Cooley‑Tukey
    for (std::size_t len = 2; len <= N; len <<= 1)
    {
        std::size_t half = len >> 1;
        std::size_t step = N / len;
#pragma omp parallel for schedule(static)
        for (std::size_t iStart = 0; iStart < N; iStart += len)
        {
            for (std::size_t j = 0; j < half; ++j)
            {
                std::size_t pos      = iStart + j;
                std::size_t posPair  = pos + half;
                Complex u = a[pos];
                Complex v = mul_by_T(a[posPair], twiddles[j * step]);

                a[pos]       = u + v;
                a[posPair]   = u - v;
            }
        }
    }

    // Write out real/imaginary parts
    for (std::size_t k = 0; k < N; ++k)
    {
        r[k] = a[k].re;
        i[k] = a[k].im;
    }
}
