#pragma once
#include <vector>

/*
 * Return true if `val` is present only in one of vectors x or y.
 * Return false if it is present in both or in neither.
 *
 * This implementation uses simple linear scans, which tends to be faster
 * than the generic std::find for small to medium-sized vectors.
 */
inline bool xorContains(const std::vector<int>& x,
                        const std::vector<int>& y,
                        int val)
{
    bool foundInX = false;
    bool foundInY = false;

    // Linear scan over x
    for (const int v : x) {
        if (v == val) {
            foundInX = true;
            break;
        }
    }

    // Linear scan over y
    for (const int v : y) {
        if (v == val) {
            foundInY = true;
            break;
        }
    }

    return foundInX ^ foundInY;
}
