};

/*
 * Convolve the edge kernel with a grayscale image.
 * imageIn  : NxN input image (row‑major).
 * imageOut : NxN output image (row‑major). Must be pre‑allocated to N*N.
 * N       : image dimension.
 *
 * The implementation uses a padded copy of the input so that we can avoid
 * bounds checking inside the inner kernel loop.  The outer loops are
 * parallelised with OpenMP to exploit the 8 available threads.
 */
void convolveKernel(std::vector<int> const& imageIn,
                    std::vector<int> &imageOut,
                    size_t N)
{
    /* Pad the input with a 1‑pixel wide border of zeros.  This removes
     * all boundary checks inside the inner loop.  The padded array has
     * dimensions (N+2) × (N+2). */
    const size_t paddedSize = (N + 2) * (N + 2);
    std::vector<int> padded(paddedSize, 0);

    /* Copy the original image into the centre of the padded array. */
    for (size_t i = 0; i < N; ++i) {
        std::memcpy(&padded[(i + 1) * (N + 2) + 1],
                    &imageIn[i * N], N * sizeof(int));
    }

    /* Parallel outer loops: we collapse the two dimensions to let
     * OpenMP distribute work more evenly across the available threads. */
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        for (size_t j = 0; j < N; ++j) {
            /* Compute the convolution sum.  The padded array guarantees
             * that all accesses are valid, so no per‑pixel boundary
             * checks are needed. */
            const int* base = &padded[(i + 1) * (N + 2) + 1];
            int sum = 0;
            sum += (-1) * base[-(N + 2) - 1] +     /* (-1,-1) */
                   (-1) * base[-(N + 2)]      +     /* (-1,0)  */
                   (-1) * base[-(N + 2) + 1] +     /* (-1,1)  */
                   (-1) * base[-1]            +     /* (0,-1)  */
                    8  * base[0]              +     /* (0,0)   */
                   (-1) * base[1]             +     /* (0,1)   */
                   (-1) * base[N + 2]         +     /* (1,-1)  */
                   (-1) * base[N + 2 + 1]     +     /* (1,0)   */
                   (-1) * base[N + 2 + 2];           /* (1,1)   */

            /* Clip the result to the 8‑bit range. */
            if (sum < 0)
                imageOut[i * N + j] = 0;
            else if (sum > 255)
                imageOut[i * N + j] = 255;
            else
                imageOut[i * N + j] = sum;
        }
    }
}
