#pragma once
#include <complex>
#include <vector>
#include <algorithm>
#include <numeric>

/* Sort the vector x of complex numbers by their magnitude in ascending order.
   Example:

   input: [3.0-1.0i, 4.5+2.1i, 0.0-1.0i, 1.0-0.0i, 0.5+0.5i]
   output: [0.5+0.5i, 0.0-1.0i, 1.0-0.0i, 3.0-1.0i, 4.5+2.1i]
*/
inline void sortComplexByMagnitude(std::vector<std::complex<double>> &x)
{
    const std::size_t n = x.size();
    if (n <= 1)
        return;

    // Pre‑compute squared magnitudes (avoids the expensive sqrt in std::abs)
    std::vector<double> mag2(n);
    for (std::size_t i = 0; i < n; ++i) {
        const double r = x[i].real();
        const double i_ = x[i].imag();
        mag2[i] = r * r + i_ * i_;
    }

    // Indirect sorting: sort indices according to the cached magnitudes
    std::vector<std::size_t> idx(n);
    std::iota(idx.begin(), idx.end(), 0);
    std::sort(idx.begin(), idx.end(),
              [&](std::size_t a, std::size_t b) { return mag2[a] < mag2[b]; });

    // Reorder the original vector according to the sorted indices
    std::vector<std::complex<double>> tmp;
    tmp.reserve(n);
    for (std::size_t i : idx)
        tmp.push_back(x[i]);

    x.swap(tmp);
}
