#include <omp.h>

/*
 * Multiply the matrix A by the matrix B. Store the results in the matrix C.
 * A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix.
 * All matrices are in row–major order.
 *
 * The routine is fully equivalent to the reference implementation but
 * uses cache‑blocking and OpenMP multi‑threading for maximum performance.
 *
 * Parameters:
 *   A (in)  : M × K matrix
 *   B (in)  : K × N matrix
 *   C (out) : M × N matrix (the caller must ensure it is zero‑initialised or
 *   otherwise contain the accumulation base values)
 */
inline void gemm(const std::vector<double>& A,
                 const std::vector<double>& B,
                 std::vector<double>&        C,
                 std::size_t                 M,
                 std::size_t                 K,
                 std::size_t                 N)
{
    /* block sizes tuned for typical L1/L2 caches on modern x86‑64 CPUs */
    constexpr std::size_t blockM = 64;
    constexpr std::size_t blockN = 64;
    constexpr std::size_t blockK = 64;

    /* parallelise over leading M dimension */
    #pragma omp parallel for schedule(static)
    for (std::size_t ii = 0; ii < M; ii += blockM) {
        const std::size_t i_end = std::min(ii + blockM, M);

        for (std::size_t jj = 0; jj < N; jj += blockN) {
            const std::size_t j_end = std::min(jj + blockN, N);

            for (std::size_t kk = 0; kk < K; kk += blockK) {
                const std::size_t k_end = std::min(kk + blockK, K);

                for (std::size_t i = ii; i < i_end; ++i) {
                    const std::size_t a_row_base = i * K;
                    const std::size_t c_row_base = i * N;

                    for (std::size_t k = kk; k < k_end; ++k) {
                        const double a_val = A[a_row_base + k];
                        const std::size_t b_row_base = k * N;

                        /* inner j loop unrolled a little for speed */
                        for (std::size_t j = jj; j < j_end; ++j) {
                            C[c_row_base + j] += a_val * B[b_row_base + j];
                        }
                    }
                }
            }
        }
    }
}
